/*@ Extern Coq (tribonacci_z: Z -> Z) */
/*@ Import Coq Require Import tribonacci */

int tribonacci(int n)
/*@ Require
      0 <= n && n <= 37 && emp
    Ensure
      __return == tribonacci_z(n@pre) && emp
*/
{
    int i;
    int a = 0;
    int b = 1;
    int c = 1;
    int d;

    if (n == 0) {
        return 0;
    }
    if (n == 1) {
        return 1;
    }

    /*@ Inv
          3 <= i && i <= n + 1 &&
          n == n@pre &&
          a == tribonacci_z(i - 3) &&
          b == tribonacci_z(i - 2) &&
          c == tribonacci_z(i - 1) &&
          emp
    */
    for (i = 3; i <= n; ++i) {
        d = a + b + c;
        a = b;
        b = c;
        c = d;
    }

    return c;
}

